36	void difftest_skip_ref() {
37	  is_skip_ref = true;
38	  // If such an instruction is one of the instruction packing in QEMU
39	  // (see below), we end the process of catching up with QEMU's pc to
40	  // keep the consistent behavior in our best.
41	  // Note that this is still not perfect: if the packed instructions
42	  // already write some memory, and the incoming instruction in NEMU
43	  // will load that memory, we will encounter false negative. But such
44	  // situation is infrequent.
45	  skip_dut_nr_inst = 0;
